using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.50m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 3, 10.00m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_ItemNotInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);
        _cart.RemoveItem("SKU-001");

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(5.00m, total);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_DoesNotThrow()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 10.00m);

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAllItems()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.50m);

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(25.50m, total);
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 1, 20.00m);
        _cart.AddItem("SKU-002", 2, 15.00m);
        _cart.RemoveItem("SKU-001");

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(30.00m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        decimal beforeCoupon = _cart.CalculateTotal();

        _cart.ApplyCoupon("SAVE10");
        decimal afterCoupon = _cart.CalculateTotal();

        Assert.IsTrue(afterCoupon < beforeCoupon,
            "Total after coupon should be less than before coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    // --- Integration / Edge-Case Tests ---

    [TestMethod]
    public void AddItem_ZeroQuantity_TotalUnchanged()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_CalledMultipleTimes_ReturnsSameValue()
    {
        _cart.AddItem("SKU-001", 2, 7.25m);

        decimal first = _cart.CalculateTotal();
        decimal second = _cart.CalculateTotal();

        Assert.AreEqual(first, second);
    }

    [TestMethod]
    public void RemoveItem_ThenAddSameItem_TotalReflectsNewItem()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");
        _cart.AddItem("SKU-001", 2, 12.00m);

        decimal total = _cart.CalculateTotal();
        Assert.AreEqual(24.00m, total);
    }
}

